// Load a Python sequence of numbers into a newly malloc'd double buffer.
// Returns buffer (caller frees) or NULL on error; sets *len.
static double* seq_to_doubles(PyObject *seq, Py_ssize_t *len) {
    PyObject *fast = PySequence_Fast(seq, "expected a sequence");
    if (!fast)
        return NULL;
    Py_ssize_t n = PySequence_Fast_GET_SIZE(fast);
    double *buf = (double *)malloc((n > 0 ? n : 1) * sizeof(double));
    if (!buf) {
        Py_DECREF(fast);
        PyErr_NoMemory();
        return NULL;
    }
    PyObject **items = PySequence_Fast_ITEMS(fast);
    for (Py_ssize_t i = 0; i < n; i++) {
        double v = PyFloat_AsDouble(items[i]);
        if (v == -1.0 && PyErr_Occurred()) {
            free(buf);
            Py_DECREF(fast);
            return NULL;
        }
        buf[i] = v;
    }
    Py_DECREF(fast);
    *len = n;
    return buf;
}

