        return NULL;
    }

    PyObject **rows = PySequence_Fast_ITEMS(cov_fast);
    double risk_squared = 0.0;
    for (Py_ssize_t i = 0; i < n; i++) {
        Py_ssize_t rlen = 0;
        double *row = seq_to_doubles(rows[i], &rlen);
        if (!row) {
            Py_DECREF(cov_fast);
            free(w);
            return NULL;
        }
        if (rlen != n) {
            PyErr_SetString(PyExc_ValueError, "covariance row size mismatch");
